let sound;
let fft;
let bins, waveform, octaveBands;
let x = 0;

function preload() {
  sound = loadSound("assets/pelagibacter.mp3");
}

function setup() {
  createCanvas(400, 512);
  fft = new p5.FFT(0.8, 512);
  fft.setInput(sound);
  noStroke();
}

function draw() {
  background(0, 5);

  // spectrogram
  bins = fft.analyze();
  for (let y = 0; y < bins.length; y++) {
    fill(bins[y], 50);
    rect(x, y, 1, 1);
  }
}
```

